func (r *repo) ListAccountsByType(ctx context.Context, ns string, accType ledger.AccountType) ([]*ledgeraccount.AccountData, error) {
	return entutils.TransactingRepo(ctx, r, func(ctx context.Context, tx *repo) ([]*ledgeraccount.AccountData, error) {
		entities, err := tx.db.LedgerAccount.Query().
			Where(ledgeraccountdb.Namespace(ns), ledgeraccountdb.AccountType(accType)).
			All(ctx)
		if err != nil {
			return nil, fmt.Errorf("list accounts by type: %w", err)
		}
		out := make([]*ledgeraccount.AccountData, 0, len(entities))
		for _, e := range entities {
			ad, err := MapAccountData(e)
			if err != nil {
				return nil, err
			}
			out = append(out, ad)
		}
		return out, nil
	})
}

func (s *service) ArchiveAccount(ctx context.Context, id models.NamespacedID) (ledger.Account, error) {
	// validate inputs before touching the repo
	if id.ID == "" || id.Namespace == "" {
		return nil, models.NewGenericValidationError("account id and namespace are required")
	}
	return transaction.Run(ctx, s.repo, func(ctx context.Context) (ledger.Account, error) {
		accData, err := s.repo.ArchiveAccount(ctx, id)
		if err != nil {
			return nil, fmt.Errorf("archive account: %w", err)
		}
		// always wrap raw data in domain object
		return account.NewAccountFromData(*accData, s.live)
	})
}
